import{_ as a,o as s,c as t,ag as n}from"./chunks/framework.CanvC6-R.js";const u=JSON.parse('{"title":"Directives","description":"","frontmatter":{},"headers":[],"relativePath":"language/language_reference/directives.md","filePath":"language/language_reference/directives.md"}'),i={name:"language/language_reference/directives.md"};function l(o,e,d,r,p,c){return s(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="directives" tabindex="-1">Directives <a class="header-anchor" href="#directives" aria-label="Permalink to &quot;Directives&quot;">​</a></h1><p>Bliss provides two compile-time naming constructs: <code>alias</code> and <code>sub</code>. Neither produces a runtime value — both are resolved entirely at compile time.</p><h2 id="alias-—-type-names" tabindex="-1"><code>alias</code> — Type Names <a class="header-anchor" href="#alias-—-type-names" aria-label="Permalink to &quot;\`alias\` — Type Names&quot;">​</a></h2><p><code>alias</code> masks an existing type under a new name. It introduces no new type — it is purely a naming convenience.</p><h3 id="syntax" tabindex="-1">Syntax <a class="header-anchor" href="#syntax" aria-label="Permalink to &quot;Syntax&quot;">​</a></h3><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>alias &lt;Type&gt; as &lt;Name&gt;</span></span></code></pre></div><h3 id="rules" tabindex="-1">Rules <a class="header-anchor" href="#rules" aria-label="Permalink to &quot;Rules&quot;">​</a></h3><ul><li>The aliased name is interchangeable with the original type everywhere a type annotation is expected.</li><li>An alias does not create a distinct type — <code>alias u8[] as String</code> does not make <code>String</code> and <code>u8[]</code> incompatible.</li></ul><h3 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h3><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>alias u8[] as String</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let name: String = &quot;Hello World&quot;;  // equivalent to let name: u8[] = &quot;Hello World&quot;</span></span></code></pre></div><hr><h2 id="sub-—-expression-names" tabindex="-1"><code>sub</code> — Expression Names <a class="header-anchor" href="#sub-—-expression-names" aria-label="Permalink to &quot;\`sub\` — Expression Names&quot;">​</a></h2><p><code>sub</code> binds a name to a valid expression. Wherever the name appears, it is replaced by the expression directly.</p><h3 id="syntax-1" tabindex="-1">Syntax <a class="header-anchor" href="#syntax-1" aria-label="Permalink to &quot;Syntax&quot;">​</a></h3><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sub &lt;name&gt; = &lt;expr&gt;</span></span></code></pre></div><h3 id="rules-1" tabindex="-1">Rules <a class="header-anchor" href="#rules-1" aria-label="Permalink to &quot;Rules&quot;">​</a></h3><ul><li>The bound expression must be a valid Bliss expression.</li><li><code>sub</code> is not a variable — it holds no memory and cannot be reassigned.</li><li>Wherever the name appears, the expression is substituted in place at compile time.</li></ul><h3 id="example-1" tabindex="-1">Example <a class="header-anchor" href="#example-1" aria-label="Permalink to &quot;Example&quot;">​</a></h3><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sub MaxAge = 100</span></span>
<span class="line"><span>sub IsAdult = age &gt;= 18</span></span>
<span class="line"><span></span></span>
<span class="line"><span>while ( IsAdult ) {</span></span>
<span class="line"><span>    // equivalent to while ( age &gt;= 18 )</span></span>
<span class="line"><span>}</span></span></code></pre></div><hr><h2 id="comparison" tabindex="-1">Comparison <a class="header-anchor" href="#comparison" aria-label="Permalink to &quot;Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th><code>alias</code></th><th><code>sub</code></th></tr></thead><tbody><tr><td>Applies to</td><td>Types</td><td>Expressions</td></tr><tr><td>Runtime value</td><td>❌</td><td>❌</td></tr><tr><td>Resolved at</td><td>Compile time</td><td>Compile time</td></tr><tr><td>Creates new type</td><td>❌</td><td>—</td></tr><tr><td>Can be reassigned</td><td>❌</td><td>❌</td></tr></tbody></table>`,22)])])}const m=a(i,[["render",l]]);export{u as __pageData,m as default};
